## 3. COMPLETE HARDENED EXPRESS.JS APPLICATION

\`\`\`javascript
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');
const { body, param, validationResult } = require('express-validator');
const jwt = require('jsonwebtoken');
const cookieParser = require('cookie-parser');
const csrf = require('csurf');
const winston = require('winston');

const app = express();
const SECRET_KEY = process.env.JWT_SECRET || 'change-me-in-production';

// ========== LOGGING ==========
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'security.log' }),
  ],
});

// ========== MIDDLEWARE ==========
app.use(helmet());
app.use(morgan('combined'));
app.use(express.json({ limit: '10kb' })); // Limit payload size
app.use(express.urlencoded({ limit: '10kb', extended: false }));
app.use(cookieParser());

// Custom security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('Content-Security-Policy', "default-src 'self'");
  next();
});

// HTTPS redirect
app.use((req, res, next) => {
  if (process.env.NODE_ENV === 'production' && !req.secure) {
    return res.redirect(301, 'https://' + req.headers.host + req.url);
  }
  next();
});

// CORS
const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
};
app.use(cors(corsOptions));

// ========== RATE LIMITING ==========
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
});

const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  skipSuccessfulRequests: true,
});

app.use(limiter);

// ========== CSRF PROTECTION ==========
const csrfProtection = csrf({ cookie: true });

// ========== AUTHENTICATION ==========
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    logger.warn('Missing auth token', { ip: req.ip, path: req.path });
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) {
      logger.warn('Invalid token', { ip: req.ip, error: err.message });
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// ========== ROUTES ==========
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.post('/login', authLimiter, (req, res) => {
  try {
    // In production: validate against database
    const user = { id: 1, username: 'testuser' };
    const token = jwt.sign(user, SECRET_KEY, { expiresIn: '1h' });
    logger.info('User logged in', { userId: user.id });
    res.json({ token });
  } catch (error) {
    logger.error('Login error', { error: error.message });
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/users', authenticateToken, (req, res) => {
  try {
    const users = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ];
    logger.info('Users list accessed', { userId: req.user.id });
    res.json(users);
  } catch (error) {
    logger.error('Users endpoint error', { error: error.message });
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/users/:id',
  param('id').isInt().toInt(),
  authenticateToken,
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const userId = parseInt(req.params.id);

    // Check authorization (IDOR protection)
    if (req.user.id !== userId && req.user.role !== 'admin') {
      logger.warn('Unauthorized access attempt', { 
        userId: req.user.id, 
        attemptedUserId: userId 
      });
      return res.status(403).json({ error: 'Forbidden' });
    }

    const user = { id: userId, name: 'Alice' };
    res.json(user);
  }
);

// ========== ERROR HANDLING ==========
app.use((err, req, res, next) => {
  logger.error('Unhandled error', { 
    error: err.message,
    url: req.url,
    method: req.method 
  });

  const statusCode = err.statusCode || 500;
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

  res.status(statusCode).json({ error: message });
});

// ========== SERVER ==========
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(\`Server running on port \${PORT}\`);
});

module.exports = app;
