# 3. Create .env.example with placeholder values instead:
# .env.example
# DATABASE_URL=postgres://user:password@host:5432/database
# AWS_ACCESS_KEY_ID=your_access_key_here
# AWS_SECRET_ACCESS_KEY=your_secret_key_here
```

---

### 2. 🔴 HIGH: Missing Authentication/Authorization
**Severity**: HIGH
**Location**: Routes `/users` and `/health`

**Issue**: No authentication is implemented. The `/users` endpoint exposes user data without any protection.

**Risk**: 
- Unauthorized users can access sensitive user information
- No role-based access control
- Data breach from public exposure

**Recommendation**:
```javascript
const express = require('express');
const app = express();

// Add authentication middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  // Verify JWT token (using jsonwebtoken library)
  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// Health endpoint - keep public but add rate limiting
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Protected endpoint - require authentication
app.get('/users', authenticateToken, (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

---

### 3. 🔴 HIGH: Missing CORS Configuration
**Severity**: HIGH
**Location**: Express app setup

**Issue**: No CORS (Cross-Origin Resource Sharing) configuration allows requests from any origin.

**Risk**: 
- CSRF (Cross-Site Request Forgery) attacks
- Unauthorized cross-origin requests to manipulate data
- XSS vulnerabilities through malicious cross-origin scripts

**Recommendation**:
```javascript
const express = require('express');
const cors = require('cors');
const app = express();

// Configure CORS - only allow trusted origins
const corsOptions = {
  origin: function (origin, callback) {
    const allowedOrigins = [
      'https://yourdomain.com',
      'https://app.yourdomain.com'
    ];

    if (!origin || allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error('Not allowed by CORS'));
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization']
};

app.use(cors(corsOptions));
```

---

### 4. 🔴 HIGH: Missing Input Validation and Sanitization
**Severity**: HIGH
**Location**: All endpoints

**Issue**: No input validation on query parameters, headers, or request bodies.

**Risk**: 
- NoSQL/SQL Injection if database is added
- XSS if user input is echoed back
- Parameter pollution attacks
- Buffer overflow or DoS through malformed requests

**Recommendation**:
```javascript
const express = require('express');
const { query, validationResult } = require('express-validator');
const app = express();

app.use(express.json({ limit: '10kb' })); // Limit payload size
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// Validate query parameters
app.get('/users', 
  query('id').optional().isInt().toInt(),
  query('limit').optional().isInt({ min: 1, max: 100 }).toInt(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    res.json([
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ]);
  }
);
```

---

### 5. 🟡 MEDIUM: Missing Security Headers
**Severity**: MEDIUM
**Location**: Express app configuration

**Issue**: No security headers (CSP, X-Frame-Options, X-Content-Type-Options, etc.)

**Risk**: 
- Clickjacking attacks
- MIME type sniffing
- XSS attacks
- Unauthorized resource loading

**Recommendation**:
```javascript
const express = require('express');
const helmet = require('helmet');
const app = express();

// Add Helmet for security headers
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'", "'unsafe-inline'"], // Remove unsafe-inline in production
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", "data:", "https:"],
    },
  },
  hsts: {
    maxAge: 31536000, // 1 year
    includeSubDomains: true,
    preload: true,
  },
  frameguard: {
    action: 'deny',
  },
  noSniff: true,
  xssFilter: true,
}));

app.use(express.json());
```

---

### 6. 🟡 MEDIUM: No Rate Limiting
**Severity**: MEDIUM
**Location**: All endpoints

**Issue**: No rate limiting on endpoints, vulnerable to brute force and DoS attacks.

**Risk**: 
- Brute force attacks on authentication endpoints (if added)
- Denial of Service (DoS) attacks
- API abuse

**Recommendation**:
```javascript
const express = require('express');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const redis = require('redis');
const app = express();

const redisClient = redis.createClient();

const limiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:',
  }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
});

// Apply rate limiting to all requests
app.use(limiter);
```

---

### 7. 🟡 MEDIUM: Missing Error Handling and Information Disclosure
**Severity**: MEDIUM
**Location**: All routes

**Issue**: No error handling middleware; stack traces could be exposed to clients.

**Risk**: 
- Information disclosure through error messages
- Stack traces reveal application structure and dependencies
- Easier for attackers to identify vulnerabilities

**Recommendation**:
```javascript
const express = require('express');
const app = express();

// Custom error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack); // Log to server

  // Don't expose stack trace to client
  const statusCode = err.statusCode || 500;
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

  res.status(statusCode).json({
    error: message,
    requestId: req.id, // For debugging without exposing internals
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});
```

---

### 8. 🟡 MEDIUM: Hardcoded Port and Missing Configuration
**Severity**: MEDIUM
**Location**: `app.listen(3000, ...)`

**Issue**: Port is hardcoded; no environment-based configuration.

**Risk**: 
- Inflexible deployment
- Potential port conflicts
- Missing configuration management

**Recommendation**:
```javascript
const express = require('express');
const app = express();

require('dotenv').config();

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${NODE_ENV} mode`);
});

module.exports = app;
```

---

### 9. 🟡 MEDIUM: Missing Logging and Monitoring
**Severity**: MEDIUM
**Location**: Entire application

**Issue**: Only basic console.log; no structured logging or security event monitoring.

**Risk**: 
- Difficult to detect and investigate security incidents
- No audit trail for compliance
- Attacks go unnoticed

**Recommendation**:
```javascript
const express = require('express');
const winston = require('winston');
const app = express();

// Structured logging
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' }),
  ],
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple(),
  }));
}

// Log all requests
app.use((req, res, next) => {
  logger.info({
    method: req.method,
    path: req.path,
    ip: req.ip,
    timestamp: new Date().toISOString(),
  });
  next();
});
```

---

### 10. 🟡 MEDIUM: Missing HTTPS Enforcement
**Severity**: MEDIUM
**Location**: Server configuration

**Issue**: Application doesn't enforce HTTPS connections.

**Risk**: 
- Man-in-the-middle (MITM) attacks
- Session hijacking
- Credential interception

**Recommendation**:
```javascript
const express = require('express');
const app = express();

// Enforce HTTPS in production
if (process.env.NODE_ENV === 'production') {
  app.use((req, res, next) => {
    if (req.header('x-forwarded-proto') !== 'https') {
      return res.redirect(307, `https://${req.header('host')}${req.url}`);
    }
    next();
  });
}
```

